{{
  (() => {
    const map = _.keyBy(GetCurrentRiskStatus.data, 'opp_id');
    const oppId = Renewal_List.selectedRow?.opportunity_id; // Achte auf den Widget-Namen; ggf. "RenewalList"
    const val = oppId ? map[oppId]?.risk_status : null;

    const defaultWithEntry = [
      "Status-Update:",
      "1. Fortschritt seit der letzten Aktualisierung: (Welche Maßnahmen wurden abgeschlossen?)",
      "2. Aktueller Status und Confidence: (Hat sich das Risikoprofil verändert? Wie ist die aktuelle Stimmung?)",
      "3. Nächste Schritte: (Welche Aktivitäten erfolgen bis zur nächsten Aktualisierung?)",
    ].join("\n");

    const defaultEmpty = [
      "Initiale Risikobewertung",
      "1. Aktuelle Situation: (Beschreiben Sie kurz den Zustand des Accounts und der Kundenbeziehung.)",
      "2. Identifizierte Risiken: (Listen Sie potenzielle Risiken auf, z. B. geringe Nutzung, Weggang wichtiger Ansprechpartner, Budgetbedenken.)",
      "3. Strategischer Maßnahmenplan: (Welche übergeordneten ersten Schritte sind nötig, um die Verlängerung abzusichern?)",
    ].join("\n");

    return val && String(val).trim().length > 0 ? defaultWithEntry : defaultEmpty;
  })()
}}
